		lastMonitorGcAt = now;
		LOGGER.info("Query circuit breaker requesting System.gc() monitorState={} freeMb={} rollingGcMs={}",
				freeMemoryState, snapshot.getFreeMemoryMb(), snapshot.getRollingGcMs());
