	private QueryPressureState determineGcState(Configuration configuration, int rollingGcMs) {
		if (rollingGcMs >= configuration.getCriticalGcMs()) {
			return QueryPressureState.CRITICAL;
		}
		if (rollingGcMs >= configuration.getHighGcMs()) {
			return QueryPressureState.HIGH;
		}
		if (rollingGcMs >= configuration.getWarnGcMs()) {
			return QueryPressureState.WARN;
		}
		return QueryPressureState.NORMAL;
	}

	private QueryPressureState determineFreeMemoryState(Configuration configuration, int freeMemoryMb) {
		if (freeMemoryMb <= configuration.getCriticalFreeMb()) {
			return QueryPressureState.CRITICAL;
		}
		if (freeMemoryMb <= configuration.getHighFreeMb()) {
			return QueryPressureState.HIGH;
		}
		if (freeMemoryMb <= configuration.getWarnFreeMb()) {
			return QueryPressureState.WARN;
		}
		return QueryPressureState.NORMAL;
	}

	private QueryPressureState capGcState(QueryPressureState gcState, QueryPressureState freeMemoryState) {
		switch (freeMemoryState) {
		case NORMAL:
			return min(gcState, QueryPressureState.WARN);
		case WARN:
			return min(gcState, QueryPressureState.HIGH);
		case HIGH:
		case CRITICAL:
		default:
			return gcState;
		}
	}

	private QueryPressureState min(QueryPressureState left, QueryPressureState right) {
		return left.ordinal() <= right.ordinal() ? left : right;
	}

	private QueryPressureState max(QueryPressureState left, QueryPressureState right) {
		return left.ordinal() >= right.ordinal() ? left : right;
	}

	private synchronized void cancelOneHeavyQueryIfNeeded(Configuration configuration,
			QueryPressureMonitor.Snapshot snapshot,
			String reason) {
		long now = clock.getAsLong();
		if (lastCancelAt != Long.MIN_VALUE && now - lastCancelAt < configuration.getCancelCooldownMs()) {
			return;
		}

		QueryCircuitBreakerHandle candidate = activeHandles.values()
				.stream()
				.filter(QueryCircuitBreakerHandle::isActive)
				.filter(QueryCircuitBreakerHandle::hasHeavyCheckpoint)
				.filter(handle -> !handle.isCancelRequested())
				.max(Comparator.comparingLong(QueryCircuitBreakerHandle::getLastHeavyCheckpointMillis))
				.orElse(null);

		if (candidate == null) {
			LOGGER.warn(
					"Query circuit breaker found no heavy query to cancel state={} freeMb={} rollingGcMs={} reason={}",
					currentState, snapshot.getFreeMemoryMb(), snapshot.getRollingGcMs(), reason);
			return;
		}

		String cancelReason = buildPressureMessage("Query cancelled by global memory circuit breaker", snapshot,
				QueryPressureState.CRITICAL);
		if (!candidate.requestCancel(QueryPressureState.CRITICAL, cancelReason)) {
			return;
		}

		lastCancelAt = now;
		cancelCount.incrementAndGet();
		LOGGER.warn(
				"Query circuit breaker cancelled executionId={} source={} repositoryId={} queryHash={} lastHeavyOperator={} reason={}",
				candidate.getExecutionId(), candidate.getSource(), candidate.getRepositoryId(),
				candidate.getQueryHash(),
				candidate.getLastHeavyOperator(), reason);
	}

	void interruptForCriticalHeavyOperator(QueryCircuitBreakerHandle handle, String operator)
			throws QueryInterruptedException {
		if (handle == null) {
			return;
		}

		Configuration configuration = configurationSupplier.get();
		QueryPressureMonitor.Snapshot snapshot = pressureMonitor.sample();
		handle.markHeavy(operator, clock.getAsLong());

		String cancelReason = buildPressureMessage("Query cancelled by global memory circuit breaker", snapshot,
				QueryPressureState.CRITICAL);
		if (handle.requestCancel(QueryPressureState.CRITICAL, cancelReason)) {
			cancelCount.incrementAndGet();
		}

		String effectiveReason = handle.getCancellationReason() != null ? handle.getCancellationReason() : cancelReason;
		throw CircuitBreakerException.cancelled(handle.getCancellationState(), configuration.getRetryAfterSeconds(),
				effectiveReason);
	}

	private String buildPressureMessage(String prefix, QueryPressureMonitor.Snapshot snapshot,
			QueryPressureState state) {
		return prefix + " (state=" + state + ", freeMb=" + snapshot.getFreeMemoryMb() + ", rollingGcMs="
				+ snapshot.getRollingGcMs() + ")";
	}

	private String normalizeRepositoryId(String repositoryId) {
		if (repositoryId == null || repositoryId.isBlank()) {
			return "unknown-repository";
		}
		return repositoryId.trim();
	}

	private String hashQuery(String queryText) {
		return Integer.toHexString(Objects.toString(queryText, "").hashCode());
	}

